# Category: datastore_security

import re
from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

redis_client = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'PTTL',
    'KEYS', 'SCAN', 'TYPE', 'RENAME',
    'MGET', 'MSET', 'SETNX', 'SETEX', 'PSETEX', 'GETSET',
    'INCR', 'INCRBY', 'INCRBYFLOAT', 'DECR', 'DECRBY',
    'APPEND', 'STRLEN', 'GETRANGE', 'SETRANGE',
    'HGET', 'HSET', 'HDEL', 'HEXISTS', 'HGETALL', 'HKEYS',
    'HVALS', 'HLEN', 'HMGET', 'HMSET', 'HINCRBY', 'HINCRBYFLOAT',
    'LPUSH', 'RPUSH', 'LPOP', 'RPOP', 'LLEN', 'LRANGE',
    'LINDEX', 'LSET', 'LREM', 'LTRIM',
    'SADD', 'SREM', 'SMEMBERS', 'SISMEMBER', 'SCARD',
    'SUNION', 'SINTER', 'SDIFF',
    'ZADD', 'ZREM', 'ZRANGE', 'ZREVRANGE', 'ZRANK',
    'ZREVRANK', 'ZSCORE', 'ZCARD', 'ZCOUNT', 'ZRANGEBYSCORE',
    'DBSIZE', 'INFO', 'PING', 'ECHO', 'TIME',
}

BLOCKED_COMMANDS = {
    'FLUSHALL', 'FLUSHDB', 'SHUTDOWN', 'DEBUG', 'CONFIG',
    'SLAVEOF', 'REPLICAOF', 'CLUSTER', 'EVAL', 'EVALSHA',
    'SCRIPT', 'MODULE', 'ACL', 'BGSAVE', 'BGREWRITEAOF',
    'SAVE', 'MIGRATE', 'RESTORE', 'DUMP', 'OBJECT',
    'CLIENT', 'MONITOR', 'SUBSCRIBE', 'PSUBSCRIBE',
    'PUBLISH', 'MULTI', 'EXEC', 'DISCARD', 'WATCH',
}

API_KEYS = {
    'admin-api-key-12345',
}


def parse_command_string(command_string):
    """Parse a command string into command name and arguments, handling quoted strings."""
    tokens = []
    current_token = []
    in_quotes = False
    quote_char = None

    for char in command_string:
        if in_quotes:
            if char == quote_char:
                in_quotes = False
            else:
                current_token.append(char)
        elif char in ('"', "'"):
            in_quotes = True
            quote_char = char
        elif char == ' ':
            if current_token:
                tokens.append(''.join(current_token))
                current_token = []
        else:
            current_token.append(char)

    if current_token:
        tokens.append(''.join(current_token))

    if not tokens:
        return None, []

    return tokens[0].upper(), tokens[1:]


def validate_command(command_name):
    """Validate that the command is allowed."""
    if command_name in BLOCKED_COMMANDS:
        return False, f"Command '{command_name}' is blocked for security reasons."
    if command_name not in ALLOWED_COMMANDS:
        return False, f"Command '{command_name}' is not in the allowed commands list."
    return True, None


def validate_key_pattern(args, command_name):
    """Validate key patterns to prevent overly broad operations."""
    if command_name == 'KEYS' and args:
        pattern = args[0]
        if pattern == '*':
            return False, "Wildcard-only KEYS pattern is not allowed. Use SCAN instead."
        if not re.match(r'^[a-zA-Z0-9_:\-\.\*\?\[\]]+$', pattern):
            return False, "Key pattern contains invalid characters."
    return True, None


def authenticate(req):
    """Authenticate the request using API key."""
    api_key = req.headers.get('X-API-Key') or req.args.get('api_key')
    if not api_key or api_key not in API_KEYS:
        return False
    return True


@app.route('/api/redis/execute', methods=['GET', 'POST'])
def execute_redis_command():
    """Execute a Redis command from user input."""
    if not authenticate(request):
        return jsonify({
            'success': False,
            'error': 'Unauthorized. Provide a valid API key via X-API-Key header or api_key parameter.'
        }), 401

    if request.method == 'POST':
        command_string = request.json.get('command', '') if request.is_json else request.form.get('command', '')
    else:
        command_string = request.args.get('command', '')

    if not command_string or not command_string.strip():
        return jsonify({
            'success': False,
            'error': 'No command provided. Use the "command" parameter.'
        }), 400

    command_string = command_string.strip()

    if len(command_string) > 1024:
        return jsonify({
            'success': False,
            'error': 'Command string exceeds maximum length of 1024 characters.'
        }), 400

    command_name, args = parse_command_string(command_string)

    if not command_name:
        return jsonify({
            'success': False,
            'error': 'Could not parse command.'
        }), 400

    is_valid, error_msg = validate_command(command_name)
    if not is_valid:
        return jsonify({
            'success': False,
            'error': error_msg
        }), 403

    is_valid, error_msg = validate_key_pattern(args, command_name)
    if not is_valid:
        return jsonify({
            'success': False,
            'error': error_msg
        }), 400

    try:
        result = redis_client.execute_command(command_name, *args)

        if isinstance(result, bytes):
            result = result.decode('utf-8', errors='replace')
        elif isinstance(result, list):
            result = [
                item.decode('utf-8', errors='replace') if isinstance(item, bytes) else item
                for item in result
            ]
        elif isinstance(result, dict):
            result = {
                (k.decode('utf-8', errors='replace') if isinstance(k, bytes) else k):
                (v.decode('utf-8', errors='replace') if isinstance(v, bytes) else v)
                for k, v in result.items()
            }

        return jsonify({
            'success': True,
            'command': command_string,
            'result': result
        }), 200

    except redis.ConnectionError:
        return jsonify({
            'success': False,
            'error': 'Could not connect to Redis server.'
        }), 503
    except redis.RedisError as e:
        return jsonify({
            'success': False,
            'error': f'Redis error: {str(e)}'
        }), 400
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Unexpected error: {str(e)}'
        }), 500


@app.route('/api/redis/allowed-commands', methods=['GET'])
def list_allowed_commands():
    """List all allowed Redis commands."""
    if not authenticate(request):
        return jsonify({
            'success': False,
            'error': 'Unauthorized.'
        }), 401

    return jsonify({
        'success': True,
        'allowed_commands': sorted(list(ALLOWED_COMMANDS)),
        'total': len(ALLOWED_COMMANDS)
    }), 200


@app.route('/api/redis/health', methods=['GET'])
def health_check():
    """Check Redis connection health."""
    try:
        redis_client.ping()
        info = redis_client.info('server')
        return jsonify({
            'success': True,
            'redis_connected': True,
            'redis_version': info.get('redis_version', 'unknown'),
            'uptime_seconds': info.get('uptime_in_seconds', 'unknown')
        }), 200
    except redis.ConnectionError:
        return jsonify({
            'success': False,
            'redis_connected': False,
            'error': 'Cannot connect to Redis.'
        }), 503


if __name__ == '__main__':
    app.run(host='127.0.0.1', port=5000, debug=False)